    "mide-balonu": { title: "Gastric Balloon (6-12 Months)", category: "Obesity Surgery", description: "A temporary balloon placed in the stomach via endoscope creates earlier satiety. No surgery required.", benefits: ["No surgery or anesthesia needed", "Same day discharge", "6 or 12 month option", "Easily reversible"] },
    "mide-botoksu": { title: "Gastric Botox", category: "Obesity Surgery", description: "Botulinum toxin injected into stomach muscles slows gastric emptying and suppresses appetite.", benefits: ["No surgery, 15-20 minutes", "Slows gastric emptying", "Suppresses appetite", "4-6 months effective duration"] },
    "tip2-diyabet": { title: "Type 2 Diabetes Operation", category: "Obesity Surgery", description: "Metabolic surgery aims to control Type 2 diabetes without medication. Over 80% complete remission is achieved.", benefits: ["80%+ Type 2 diabetes remission", "Incretin hormone increase", "Pancreatic beta cell activation", "Long-term metabolic health"] },
    "lazer-goz": { title: "Excimer Laser (Eye Laser)", category: "Eye Operations", description: "Excimer Laser permanently corrects myopia, hyperopia and astigmatism. Includes LASIK, LASEK and TransPRK techniques.", benefits: ["LASIK, LASEK, TransPRK options", "Freedom from glasses and lenses", "Clear vision within hours", "99%+ patient satisfaction"] },
    "katarakt-ameliyati": { title: "Cataract Surgery", category: "Eye Operations", description: "In modern phacoemulsification, the clouded lens is broken up by ultrasound waves and removed. The procedure takes an average of 10-15 minutes.", benefits: ["2-3 mm micro incision, no sutures", "Eye drops anesthesia sufficient", "10-15 minute operation", "Same day discharge"] },
