    "emax-tac": { title: "تاج Emax", category: "علاجات الأسنان", description: "تاج Emax مصنوع من السيراميك الزجاجي بسيليكات الليثيوم، وهو نظام تاج أسنان متميز يجمع بين الجماليات والمتانة.", benefits: ["جماليات فائقة", "خالية من المعادن", "مقاومة عالية للكسر", "نقل الضوء الطبيعي"] },
