    "veneer": { title: "عدسات الأسنان", category: "علاجات الأسنان", description: "عدسات الأسنان عبارة عن طلاء بورسلين أو مركب رقيق جداً يتم لصقه على السطح الأمامي للأسنان. يتم الحصول على ابتسامة مثالية باستخدام طريقة طفيفة التوغل.", benefits: ["حد أدنى من برد الأسنان", "مظهر طبيعي", "طويل الأمد", "مقاوم للبقع"] },
