    "emax-tac": { title: "Corona Emax", category: "Trattamenti Dentali", description: "La corona Emax, realizzata in ceramica al silicato di litio, è un sistema di corona dentale premium che combina estetica e durabilità.", benefits: ["Estetica superiore", "Senza metallo", "Alta resistenza alla frattura", "Trasmissione di luce naturale"] },
